return ['domain'=>'visibility-controls-for-editor-blocks','plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10 >= 2 && n%10<=4 &&(n%100<10||n%100 >= 20)? 1 : 2);','language'=>'ru_RU','project-id-version'=>'Visibility Controls for Editor Blocks 1.0.3','pot-creation-date'=>'2024-10-11T19:01:50+00:00','po-revision-date'=>'2024-11-03 16:29+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Adds controls to hide blocks on mobile, tablet, and desktop devices in Gutenberg.'=>'Добавляет элементы управления для скрытия блоков на мобильных, планшетных и настольных устройствах в Gutenberg.','Advanced Settings'=>'Расширенные настройки','Any screen wider than the tablet breakpoint will be considered a desktop.'=>'Любой экран, ширина которого превышает значение контрольной точки планшета, будет считаться настольным устройством.','Blocks hidden on mobile will be hidden on screens this size or smaller.'=>'Блоки, скрытые на мобильных устройствах, будут скрыты на экранах заданного размера или меньше.','Blocks hidden on tablets will be hidden on screens this size or smaller.'=>'Блоки, скрытые на планшетах, будут скрыты на экранах заданного размера или меньше.','Breakpoints Settings'=>'Настройки контрольных точек','Configure Breakpoints'=>'Настройки контрольных точек','Configure the breakpoints for mobile, tablet and desktop devices.'=>'Настройте контрольные точки для мобильных, планшетных и настольных устройств.','Desktop Breakpoint (px)'=>'Контрольная точка для настольных устройств (px)','Disable CSS loading on pages without Gutenberg'=>'Отключить загрузку CSS стилей на страницах без Gutenberg блоков','Gutenberg Blocks Visibility'=>'Видимость Блоков Gutenberg','Hidden for Logged-in Users'=>'Скрыто для вошедших пользователей','Hidden for Non-Logged-in Users'=>'Скрыто для НЕ вошедших пользователей','Hidden on Desktop'=>'Скрыт на настольных устройствах','Hidden on Mobile'=>'Скрыт на мобильных устройствах','Hidden on Tablet'=>'Скрыт на планшетах','Hide for Logged-in Users'=>'Скрыть для вошедших пользователей','Hide for Non-Logged-in Users'=>'Скрыть для НЕ вошедших пользователей','Hide on Desktop'=>'Скрыть на настольных устройствах','Hide on Mobile'=>'Скрыть на мобильных устройствах','Hide on Tablet'=>'Скрыть на планшетах','Leave a Review'=>'Оставить отзыв','Mobile Breakpoint (px)'=>'Контрольная точка для мобильных устройств (px)','Note: '=>'Примечание: ','Recommended: between 320px and 600px for mobiles.'=>'Рекомендуемый размер: от 320px до 600px для мобильных устройств.','Recommended: between 601px and 1024px for tablets.'=>'Рекомендуемый размер: от 601px до 1024px для планшетов.','Settings'=>'Настройки','Styles loading'=>'Загрузка стилей','Tablet Breakpoint (px)'=>'Контрольная точка для планшетов (px)','There\'s no input for the desktop breakpoint because it is automatically defined'=>'Контрольную точку для настольных устройств вводить не нужно, поскольку она определяется автоматически','This includes archive pages such as categories and tags, as well as other pages that do not contain Gutenberg blocks.'=>'Сюда входят архивные страницы, такие как категории и теги, а также другие страницы, не содержащие блоков Gutenberg.','This option defines the screen width (in pixels) that determines a mobile device.'=>'Этот параметр задает ширину экрана (в пикселях), которую определяет мобильное устройство.','This option defines the screen width (in pixels) that determines a tablet device.'=>'Этот параметр задает ширину экрана (в пикселях), которая определяет планшетное устройство.','Visibility Controls for Editor Blocks'=>'Контроль видимости для Gutenberg блоков','Visibility Controls for Gutenberg Blocks'=>'Контроль видимости для Gutenberg блоков','Visibility Settings'=>'Настройки видимости','When this option is enabled, the plugin will prevent loading its CSS code on pages that do not use the Gutenberg editor.'=>'Если эта опция включена, плагин не будет загружать CSS стили на страницах, не использующих редактор Gutenberg.','Video guide'=>'Видеоинструкция','Watch short tutorials for setting up block visibility rules.'=>'Посмотрите короткие инструкции по настройке правил видимости блоков.','Open video playlist'=>'Открыть плейлист с видео','Enjoying Visibility Controls?'=>'Нравится Visibility Controls?','If this plugin saves you time, a quick review on WordPress.org helps other Gutenberg users find it.'=>'Если плагин экономит вам время, короткий отзыв на WordPress.org поможет другим пользователям Gutenberg его найти.','Maybe later'=>'Позже','Do not ask again'=>'Больше не спрашивать','Support the plugin'=>'Поддержать плагин','Want to support future updates? You can buy me a coffee.'=>'Хотите поддержать будущие обновления? Вы можете купить мне кофе.','Buy me a coffee'=>'Купить мне кофе','Donate'=>'Поддержать','and Tablet'=>' и планшетах','and Desktop'=>' и настольных устройствах','and Logged-in Users'=>' и для вошедших пользователей','and Non-Logged-in Users'=>' и для НЕ вошедших пользователей','Denis Doroshchuk'=>'Денис Дорощук','https://doroshchuk.me/'=>'https://doroshchuk.me/']];